        pulse.write_to_timer_low(0xFF);
        pulse.write_to_timer_high(0b0000_0111);
        pulse.write_to_sweep(0b1001_0001);

        assert_eq!(pulse.sweep_target(), 0x0BFE);
        assert_eq!(pulse.output(), 0);
    }
